const execution = $json.execution || {};
const workflow = $json.workflow || {};
const error = execution.error || $json.error || {};
const occurredAt = new Date().toISOString();
const displayAt = new Date().toLocaleString('pt-BR', {
  timeZone: 'America/Sao_Paulo',
  year: 'numeric',
  month: '2-digit',
  day: '2-digit',
  hour: '2-digit',
  minute: '2-digit',
  second: '2-digit',
});
const workflowName = workflow.name || $json.workflowName || 'Workflow desconhecido';
const node = execution.lastNodeExecuted || error.node?.name || error.node || 'Nó não informado';
const message = error.message || error.description || $json.message || 'Erro sem descrição';
const stack = String(error.stack || error.context || '').slice(0, 1200);
const executionUrl = execution.url || execution.resumeUrl || '';
const centralPayload = {
  source: 'n8n',
  workflow: workflowName,
  node,
  message,
  stack,
  executionUrl,
  occurredAt,
};
const whatsappMessage = [
  '🚨 Erro no n8n',
  '',
  `Data/hora: ${displayAt}`,
  `Workflow: ${workflowName}`,
  `Nó: ${node}`,
  `Erro: ${message}`,
  executionUrl ? `Execução: ${executionUrl}` : '',
  stack ? `Log: ${stack.slice(0, 900)}` : '',
].filter(Boolean).join('\n');

return {
  json: {
    ...centralPayload,
    whatsappMessage,
    centralPayload,
  },
};
